{
  "summary": "This paper proposes language-based methods, including a novel adaptive tagging pipeline (STEP-Tag), to approximate human similarity judgments efficiently across images, audio, and video modalities. It demonstrates that combining language embeddings with domain-specific DNN embeddings improves approximation quality and scalability compared to prior approaches relying solely on deep models or exhaustive human judgments.",
  "strengths": [
    {
      "point": "Comprehensive large-scale evaluation of over 600 pre-trained models across multiple modalities",
      "evidence": "Evaluated 611 models on images, audio, and video, comparing their internal representations to human similarity judgments."
    },
    {
      "point": "Introduction of STEP-Tag, an adaptive crowdsourcing pipeline for collecting high-quality, diverse semantic tags without a predefined taxonomy",
      "evidence": "STEP-Tag iteratively refines tags via participant ratings and additions, yielding more informative and diverse tags than baselines."
    },
    {
      "point": "Novel language-based similarity approximation methods that scale linearly with dataset size",
      "evidence": "Using LLM embeddings and Word Frequency Analysis on textual descriptors enables O(N) cost similarity approximations, validated across modalities."
    },
    {
      "point": "Stacked embedding approach combining DNN and LLM embeddings improves similarity approximation performance",
      "evidence": "Stacked methods consistently outperform single-modality embeddings and jointly trained multi-modal models like CLIP."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of benchmarking against established semantic similarity methods from NLP literature",
      "evidence": "No experiments or detailed discussion comparing proposed language-based methods to baselines like GloVe, FastText, or Sentence-BERT."
    },
    {
      "point": "Insufficient methodological details and reproducibility information for STEP-Tag and embedding extraction",
      "evidence": "Missing critical details on crowdsourcing platform, participant recruitment, quality control, hyperparameter tuning, and preprocessing pipelines."
    },
    {
      "point": "Evaluation relies heavily on correlation metrics without complementary analyses or downstream task validation",
      "evidence": "No use of ranking, clustering, or retrieval metrics; no qualitative analyses or practical task evaluations reported."
    },
    {
      "point": "Limited discussion and analysis of biases, data quality, and potential overfitting or data leakage",
      "evidence": "No inter-rater agreement statistics, noise handling, or clear data splits to prevent leakage between tag collection and evaluation."
    },
    {
      "point": "Missing statistical rigor such as significance testing and confidence intervals for reported improvements",
      "evidence": "Correlation improvements are reported without p-values or confidence intervals."
    },
    {
      "point": "Underexplored generalizability beyond images, audio, and video, and limitations of language-based methods for non-textual modalities",
      "evidence": "No empirical validation or discussion of applicability to text or specialized domains like medical imaging."
    }
  ],
  "questions": [
    {
      "question": "How do the proposed language-based similarity approximations compare quantitatively to established semantic similarity methods from NLP?",
      "motivation": "Benchmarking against known baselines is necessary to clarify the novelty and practical advantage of the approach."
    },
    {
      "question": "What are the computational costs and scalability implications of extracting and stacking embeddings from hundreds of models?",
      "motivation": "Understanding resource requirements is critical for assessing feasibility in large-scale or real-world applications."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
